#include <bits/stdc++.h> 
using namespace std;
const int N=1005;
const long long INF=-1e18;
long long dp[N][N],a[N][N],s,k,c,t,n,m,ans,dx[]={0,0,0,1},dy[]={0,1,-1,0};
struct node
{
	int x,y;
};
long long read()
{
    long long x = 0,f=1;
    char ch = getchar();
    while (ch < '0' || ch > '9')
	{
        if (ch == '-') f = -1;
        ch = getchar();
    }
    while (ch >= '0' && ch <= '9')
	{
        x = x * 10 + (ch - '0');
        ch = getchar();
    }
    return x*f;
}
void write(long long x)
{
    if(x<0)
	{
        putchar('-');
        x=-x;
    }
    if(x>9) write(x/10);
    putchar(x%10+'0');
}
int main()
{
//	freopen("journey8.in","r",stdin);
//	freopen("journey8.out","w",stdout);
	c=read();
	t=read();
	while(t--)
	{
		memset(dp,128,sizeof(dp));
		ans=-1;
		n=read();
		m=read();
		s=read();
		k=read();
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=m;j++)
			{
				a[i][j]=read();
				if(a[i][j]>k)
				{
					a[i][j]=k;
				}
			}
			if(i==n) continue; 
			for(int j=1;j<=m;j++)
			{
				if(a[i][j]>0)
				{
					if(j>1&&a[i][j]+a[i][j-1]>0)
					{
						a[i][j]=k;
					}
					else if(j<m&&a[i][j]+a[i][j+1]>0) a[i][j]=k;
				}
			}
		}

		for(int i=1;i<n;i++)
		{
			int t=5;
			while(t--)
			{
				if(t%2==1)
				{
					for(int j=m;j>=1;j--)
					{
						dp[i][j]=max(dp[i][j],max(dp[i][j-1]+a[i][j],max(dp[i][j+1]+a[i][j],dp[i-1][j]+a[i][j])));
	                    if(dp[i][j]<0) dp[i][j]=INF;
	                    if(dp[i][j]>k) dp[i][j]=k;
					}
					continue;
				}
				for(int j=1;j<=m;j++)
				{
                    if(i==1&&t==4) dp[i][j]=s+a[i][j];
					dp[i][j]=max(dp[i][j],max(dp[i][j-1]+a[i][j],max(dp[i][j+1]+a[i][j],dp[i-1][j]+a[i][j])));
                    if(dp[i][j]<0) dp[i][j]=INF;
                    if(dp[i][j]>k) dp[i][j]=k;
				}
			}
		}
        for(int i=1;i<=m;i++) ans=max(dp[n-1][i]+a[n][i],ans);
		write(ans);
		cout<<'\n';
	}
	return 0;
}
